def hub_page(c):
 missions=[
 ('001','The Proof Gradient','Where autonomous work earns the right to become capability.','proof-gradient-challenge.html'),
 ('002','The Ascension Protocol','Where proven capability learns to travel.','proof-mission-002.html'),
 ('003','The Capability Constellation','Where proven capabilities become a governed intelligence.','proof-mission-003.html'),
 ('004','The Sovereign Institution','Where governed intelligence learns to endure.','proof-mission-004.html'),
 ('005','The Interinstitutional Accord','Where sovereign institutions cooperate without surrendering sovereignty.','proof-mission-005.html'),
 ('006','The Long Horizon','Where governed intelligence proves it can remain faithful across generations.','proof-mission-006.html'),
 ('007','The Civilizational Covenant','Where continuity becomes stewardship—without sovereignty over humanity.','proof-mission-007.html')]
 cards=''.join(f'<article class="cv-mission-card {"active" if num=="007" else ""}"><strong>PUBLIC PROOF MISSION {num}</strong><h2>{esc(title)}</h2><p>{esc(copy)}</p><a href="{href}">Enter mission →</a></article>' for num,title,copy,href in missions)
 return f'''<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>GoalOS Public Proof Missions 001–007</title>{css()}</head><body><main class="cv-hub"><div class="cv-shell"><div class="cv-eyebrow">GoalOS AGIALPHA Ascension</div><h1>THE PUBLIC<br>PROOF MISSIONS</h1><p style="max-width:820px;font-size:1.15rem;line-height:1.75;color:#c8d6dc">Capability. Transfer. Composition. Institution. Accord. Continuity. Stewardship. Seven protocols for turning autonomous work into governed, replayable, reversible institutional capability.</p><div class="cv-hub-grid">{cards}</div><article class="cv-mission-card" style="margin-top:1rem"><strong>MISSION 008 HORIZON</strong><h2>{esc(c['mission8']['title'])}</h2><p>{esc(c['mission8']['copy'])}</p><span class="cv-status">HORIZON ONLY · NOT AUTHORIZED</span></article><p style="margin-top:2rem"><a class="cv-btn" href="index.html">Return to GoalOS</a></p></div></main></body></html>'''

def home_style(): return f'''{STYLE_START}{css()}{STYLE_END}'''
def home_section():
 return f'''{START}<section class="cv-home"><div class="cv-home-in"><div><small>PUBLIC PROOF MISSION 007 · PLURAL STEWARDSHIP</small><h2>THE CIVILIZATIONAL <span>COVENANT</span></h2><p><strong>Where continuity becomes stewardship—without sovereignty over humanity.</strong> Mission 007 publishes a bounded protocol for shared public goods, protected rights, externality accounting, independent challenge, constitutional fork, portable exit, rollback, human renewal, and dignified dissolution.</p><div class="cv-home-law">No stewardship without consent. No shared future without plural sovereignty. No covenant without rights, dissent, exit, rollback, and the power to end.</div><div class="cv-home-actions"><a href="{PAGE}">Enter Mission 007</a><a href="{HUB}">Open the Proof Missions</a></div></div><div class="cv-home-orbit"><i></i><i></i><i></i><div class="cv-home-core">M7<br>STEWARDSHIP</div></div></div></section>{END}'''

def replace_marked(t,s,e,r):
 if t.count(s)!=1 or t.count(e)!=1: fail(f'marker count mismatch: {s}')
 return re.sub(re.escape(s)+r'.*?'+re.escape(e),r,t,count=1,flags=re.S)

def inject_home(p):
 p=Path(p); raw=p.read_text(encoding='utf-8'); st=home_style(); sec=home_section()
 raw=replace_marked(raw,STYLE_START,STYLE_END,st) if STYLE_START in raw else raw.replace('</head>',st+'\n</head>',1)
 if START in raw: raw=replace_marked(raw,START,END,sec)
 elif M6_END in raw: raw=raw.replace(M6_END,M6_END+'\n'+sec,1)
 else: fail('Mission 006 homepage marker not found')
 p.write_text(raw,encoding='utf-8')

def promote_m6(p):
 p=Path(p); raw=p.read_text(encoding='utf-8')
 active=f'''{PROMO_START}<article class="horizon"><strong>PUBLIC PROOF MISSION 007 · NOW PUBLISHED</strong><h2>The Civilizational Covenant</h2><p>Mission 007 publishes the bounded protocol for plural stewardship of public goods, rights, knowledge commons, externalities, crisis response, constitutional fork, portable exit, rollback, human renewal, and dignified dissolution.</p><p><a class="btn primary" href="proof-mission-007.html">Enter Mission 007</a></p></article>{PROMO_END}'''
 if PROMO_START in raw: raw=replace_marked(raw,PROMO_START,PROMO_END,active)
 else:
  raw,n=re.subn(r'<article class="horizon"><strong>MISSION 007 HORIZON</strong>.*?</article>',active,raw,count=1,flags=re.S)
  if n!=1: fail('Mission 006 horizon not found')
 p.write_text(raw,encoding='utf-8')

def downloads(site,c,m):
 out=Path(site)/'downloads/proof-missions'; out.mkdir(parents=True,exist_ok=True); dump(out/'public-proof-mission-007.json',c)
 templates={
 'mission-007-covenant-charter-template.json':{'humanAuthorityRoots':[],'reservedPowers':[],'rightsFloor':[],'publicGoodScope':{},'status':'TEMPLATE_NOT_EVIDENCE'},
 'mission-007-public-good-ledger-template.json':{'objectives':[],'beneficiaries':[],'costs':[],'outcomes':[],'uncertainty':[],'status':'TEMPLATE_NOT_EVIDENCE'},
 'mission-007-rights-exit-register-template.json':{'affectedGroups':[],'rights':[],'challenges':[],'appeals':[],'exits':[],'forks':[],'status':'TEMPLATE_NOT_EVIDENCE'},
 'mission-007-externality-accounting-template.json':{'direct':[],'indirect':[],'delayed':[],'ecological':[],'distributional':[],'liabilities':[],'status':'TEMPLATE_NOT_EVIDENCE'},
 'mission-007-renewal-dissolution-template.json':{'finalDisposition':'NOT_SELECTED','renewal':None,'narrowing':None,'fork':None,'archive':None,'dissolution':None,'status':'TEMPLATE_NOT_EVIDENCE'} }
 for name,v in templates.items(): v.update({'schemaVersion':'1.0','missionId':c['missionId']}); dump(out/name,v)
 by={x['name']:x for x in m['contracts']}
 with (out/'mission-007-proof-route.csv').open('w',newline='',encoding='utf-8') as f:
  w=csv.DictWriter(f,fieldnames=['sequence','stage','contract','address','purpose','etherscan_url']); w.writeheader()
  for x in c['proofRoute']:
   d=by[x['contractName']]; w.writerow({'sequence':x['sequence'],'stage':x['stage'],'contract':x['contractName'],'address':d['address'],'purpose':x['purpose'],'etherscan_url':d['etherscanUrl']})

def main():
 ap=argparse.ArgumentParser(); ap.add_argument('--site',default='site'); ap.add_argument('--content',default='content/proof-mission-007-civilizational-covenant.json'); ap.add_argument('--mainnet',default='data/mainnet/v4.4.0-mainnet-2026-06-21.json'); a=ap.parse_args()
 site=Path(a.site); cp=Path(a.content); mp=Path(a.mainnet); c=load(cp); m=load(mp); validate(c,m)
 req=[site/'index.html',site/'proof-missions.html',site/'proof-gradient-challenge.html',site/'proof-mission-002.html',site/'proof-mission-003.html',site/'proof-mission-004.html',site/'proof-mission-005.html',site/'proof-mission-006.html']
 miss=[str(x) for x in req if not x.is_file() or x.stat().st_size==0]
 if miss: fail('Build Missions 001–006 first: '+', '.join(miss))
 preserve=[site/'proof-gradient-challenge.html',site/'proof-mission-002.html',site/'proof-mission-003.html',site/'proof-mission-004.html',site/'proof-mission-005.html']
 prior={x.name:sha(x) for x in preserve}
 (site/PAGE).write_text(page(c,m),encoding='utf-8'); (site/HUB).write_text(hub_page(c),encoding='utf-8'); inject_home(site/'index.html'); promote_m6(site/'proof-mission-006.html'); downloads(site,c,m)
 for x in preserve:
  if sha(x)!=prior[x.name]: fail(x.name+' changed unexpectedly')
 qa={'status':'PASS','missionId':c['missionId'],'proofRouteStages':48,'validatorQuorum':8,'covenants':8,'mission001To005Preserved':True,'mission006HorizonPromoted':True,'publicNetworkTransactionSent':False,'contentSha256':sha(cp),'mainnetDataSha256':sha(mp)}
 dump(site/'qa/proof-mission-007-build.json',qa); print(json.dumps(qa,indent=2)); return 0
if __name__=='__main__': raise SystemExit(main())
